SELECT 
FROM homework_submission hs
LEFT JOIN student s ON hs.student_id = s.id
LEFT JOIN class_entity c ON hs.class_id = c.id
LEFT JOIN sys_user u ON hs.grader_id = u.id
WHERE hs.is_deleted = 0

    AND hs.homework_id = #{homeworkId}


    AND hs.student_id = #{studentId}


    AND hs.grade_status = #{gradeStatus}

ORDER BY hs.submit_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM homework_submission hs
WHERE hs.is_deleted = 0

    AND hs.homework_id = #{homeworkId}


    AND hs.student_id = #{studentId}


    AND hs.grade_status = #{gradeStatus}

SELECT id, homework_id, student_id, submit_time, is_late, grade_status, score
FROM homework_submission
WHERE homework_id = #{homeworkId}
AND student_id = #{studentId}
AND is_deleted = 0
LIMIT 1

SELECT s.id as studentId, s.name as studentName, s.student_no as studentNo
FROM student s
WHERE s.class_id = (
    SELECT class_id FROM homework WHERE id = #{homeworkId}
)
AND s.is_deleted = 0
AND s.id NOT IN (
    SELECT student_id FROM homework_submission
    WHERE homework_id = #{homeworkId}
    AND is_deleted = 0
)
